traintEqualToAnchor:_title.bottomAnchor constant:3],[_detail.leadingAnchor constraintEqualToAnchor:_title.leadingAnchor],[_detail.trailingAnchor constraintEqualToAnchor:_title.trailingAnchor],[_detail.bottomAnchor constraintEqualToAnchor:self.contentView.bottomAnchor constant:-9]]]; return self; }
