r:_title.leadingAnchor],[_detail.trailingAnchor constraintEqualToAnchor:_title.trailingAnchor],[_detail.bottomAnchor constraintLessThanOrEqualToAnchor:self.contentView.bottomAnchor constant:-8]]]; return self; }
